import React, { useContext } from 'react';
import { AppContext } from '../context/AppContext';

const CatalogPage = () => {
  const { products, user, createOrder } = useContext(AppContext);

  return (
    <div style={{ padding: '20px' }}>
      <h1>Каталог кроссовок</h1>
      <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
        {products.map(item => (
          <div key={item.id} style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '8px' }}>
            <h3>{item.name}</h3>
            <p>Цена: {item.price} KZT</p>
            {user ? (
              <button onClick={() => createOrder([item])}>Купить</button>
            ) : (
              <p style={{ color: 'gray', fontSize: '12px' }}>Войдите, чтобы купить</p>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default CatalogPage;
